def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
        else:
            ratio = item / capacity
            priority = 0
            if ratio < 0.3:
                priority += (1 - ratio) ** 3 * 15
            elif 0.3 <= ratio < 0.7:
                priority += np.sqrt(ratio) * 8
                if ratio > 0.5:
                    for k in range(1, int(capacity) + 1):
                        if capacity % k == 0 and k < item:
                            priority += k * 0.1
            elif 0.7 <= ratio <= 1:
                priority += np.log1p(ratio) * 10
                for m in range(1, 5):
                    priority += (ratio * m) % 1 * 3
            else:
                penalty = 0
                int_ratio = int(ratio)
                for j in range(1, int_ratio + 1):
                    if abs(ratio % j) < 1e-6:
                        penalty += j * 2
                penalty += sum([((ratio - int_ratio) * x) for x in range(1, 4)])
                priority += penalty + (ratio - 1) * 25
                if ratio > 2:
                    for n in range(1, int(capacity // 2) + 1):
                        if capacity % n == 0:
                            priority += np.log1p(n) * 0.5
            priorities[i] = priority
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 150)
    return priorities
